import React from "react";
import { PageProps } from "gatsby";
import { useLocation } from "@reach/router";
import Header from "../../componets/header/Header";
import Footer from "../../componets/footer/Footer";
import EventHero from "../../componets/EventHero/EventHero";
import EventSection from "../../componets/EventAbout/EventAbout";
import SponsorsSection from "../../componets/SponsorsSection/SponsorsSection";
import TestimonialsSection from "../../componets/TestimonialsSection";
import EventSpeakers from "../../componets/EventSpeakers/EventSpeakers";
import PriceList from "../../componets/PriceList/PriceList";
import EventAttendees from "../../componets/EventAttendees/EventAttendees";
import { events } from "../../data/events";

const DynamicEventPage: React.FC<PageProps> = () => {
  const location = useLocation();
  const eventSlug = location.pathname.split("/")[2];
  const eventData = events.find(e => e.id === eventSlug);

  if (!eventData) {
    return (
      <main style={{ background: '#1A202C', minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
        <Header />
        <div style={{ color: 'white', textAlign: 'center', padding: '2rem' }}>
          <h1 style={{ fontSize: '2rem', marginBottom: '1rem', color: '#D1A12A' }}>Event Not Found</h1>
          <p>The event you're looking for doesn't exist.</p>
        </div>
        <Footer />
      </main>
    );
  }

  const handleScrollToPricing = () => {
    const el = document.getElementById("pricing");
    if (el) el.scrollIntoView({ behavior: "smooth" });
  };

  return (
    <main style={{ background: '#1A202C', minHeight: '100vh' }}>
      <Header />
      <EventHero
        eventName={eventData.name}
        eventDate={eventData.date}
        location={eventData.location}
        remainingTickets={eventData.remainingTickets}
        speakersCount={eventData.speakersCount}
        onRegisterClick={handleScrollToPricing}
      />
      <EventSection data={eventData?.about} />
      <EventSpeakers speakers={eventData?.speakers} />
      <SponsorsSection sponsors={eventData?.sponsors} />
      <TestimonialsSection testimonials={eventData?.testimonials} />
      <PriceList pricing={eventData?.pricing} />
      <EventAttendees attendees={eventData?.attendees} />
      <Footer />
    </main>
  );
};

export default DynamicEventPage;

export const Head = ({ location }: { location: { pathname: string } }) => {
  const eventSlug = location.pathname.split("/")[2];
  const eventData = events.find(e => e.id === eventSlug);
  
  return (
    <>
      <title>{eventData?.name || "Event"} - Registration</title>
      <meta name="description" content={eventData?.about.description || "Join our amazing event"} />
    </>
  );
};